class Solution:
    def nthPersonGetsNthSeat(self, n: int) -> float:
        if n == 1:
            return 1.0
        # simulate by exhaustive probability tracing for small n (brute)
        from fractions import Fraction
        # dp[i] = prob nth person gets nth seat given i seats
        dp = {1: Fraction(1)}
        for k in range(2, n + 1):
            # first person picks uniformly among k seats
            # seat 1: (1/k) * 1
            # seat k: (1/k) * 0
            # seat j (2..k-1): (1/k) * dp[k-1]
            p = Fraction(1, k) * 1 + Fraction(k - 2, k) * dp[k - 1] + Fraction(1, k) * 0
            dp[k] = p
        return float(dp[n])

